('UPDATE','2023-09-08 08:38:08',260,43,1,359,'2022-10-30 20:56:23',101,'2022-11-01 12:12:38','MEMO INFORME SEMANAL ','<p><strong>A </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <strong>#destinatario#</strong></p>\r\n\r\n<p><strong>De </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#remitente#</strong></p>\r\n\r\n<p><strong>Cc:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;#concopia#</strong></p>\r\n\r\n<p><strong>Asunto:&nbsp; &nbsp; &nbsp; &nbsp; #asunto#</strong></p>\r\n\r\n<p><strong>Fecha </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#fecha#</strong></p>\r\n\r\n<hr />\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,&quot;serif&quot;\">En Respuesta al MEMOR&Aacute;NDUM DPD N&ordm; 11/2022, cumplo en remitir el informe de trabajo realizado desde el d&iacute;a 26&nbsp;de octubre al 01 de noviembre, acorde al cronograma de actividades.</span></span></span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,&quot;serif&quot;\">Atentamente,</span></span></span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><strong><span style=\"font-size:12.0pt\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,&quot;serif&quot;\">DEPARTAMENTO DE AN&Aacute;LISIS Y ESTAD&Iacute;STICAS</span></span></span></strong></span></span></span></p>\r\n\r\n<ol>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,&quot;serif&quot;\">26/10/2022 Remisi&oacute;n a la Direcci&oacute;n de Planificaci&oacute;n el procesamiento de la informaci&oacute;n estad&iacute;stica, detallando la <strong>cantidad de votos individualizado por Miembros</strong> para la obtenci&oacute;n de la Sentencia en las causas finiquitadas de acuerdo al orden del d&iacute;a de la Sesi&oacute;n del 25/10/2022. (remitido por mail y por Whatsapp en formato PDF al Se&ntilde;or Director General de Gabinete).</span></span></span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,&quot;serif&quot;\">26/10/2022 Recepci&oacute;n de informe de Secretar&iacute;a Jur&iacute;dica sobre la Sesi&oacute;n de fecha 25/10/2022, por parte del compa&ntilde;ero Abg. Rodney Z&aacute;rate.</span></span></span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,&quot;serif&quot;\">26/10/2022 Remisi&oacute;n a la Direcci&oacute;n de Planificaci&oacute;n, el procesamiento de Datos y conclusi&oacute;n en la informaci&oacute;n estad&iacute;stica, sobre el <strong>estudio de las causas del orden del d&iacute;a 25/10/2022</strong>, y posterior conclusi&oacute;n de acuerdo a las decisiones adoptadas por el Pleno. (remitido por mail y por Whatsapp en formato PDF al Se&ntilde;or director General de Gabinete).</span></span></span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,&quot;serif&quot;\">26/10/2022 Remisi&oacute;n a la Direcci&oacute;n de Planificaci&oacute;n, el procesamiento de Datos y conclusi&oacute;n en la informaci&oacute;n estad&iacute;stica, sobre el <strong>movimiento de expedientes de diciembre 2021 al 25/10/2022. </strong>(remitido por mail y por Whatsapp en formato PDF al Se&ntilde;or Director General de Gabinete).</span></span></span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,&quot;serif&quot;\">26/10/2022 Remisi&oacute;n a la Direcci&oacute;n de Planificaci&oacute;n, el procesamiento de Datos y conclusi&oacute;n en la informaci&oacute;n estad&iacute;stica, sobre las <strong>causas rechazadas, archivadas y canceladas de manera hist&oacute;rica desde el 2012 a la fecha 25/10/2022. </strong>(remitido por mail y por Whatsapp en formato PDF al Se&ntilde;or Director General de Gabinete).</span></span></span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,&quot;serif&quot;\">26/10/2022 Remisi&oacute;n a la Direcci&oacute;n de Planificaci&oacute;n, el procesamiento de Datos y conclusi&oacute;n en la informaci&oacute;n estad&iacute;stica, sobre las <strong>sentencias dictadas&nbsp; desde el 2014 a la fecha 25/10/2022. </strong>(remitido por mail y por Whatsapp en formato PDF al Se&ntilde;or Director General de Gabinete).</span></span></span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,&quot;serif&quot;\">26/10/2022 Remisi&oacute;n de Datos estad&iacute;sticos actualizados a la fecha sobre <strong>causas ingresadas a la instituci&oacute;n. </strong>(remitido por mail y por Whatsapp en formato PDF al Se&ntilde;or Director General de Gabinete).</span></span></span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,&quot;serif&quot;\">26/10/2022 Remisi&oacute;n de Datos Estad&iacute;sticos actualizados <strong><em>de acuerdo al Saldo de Expedientes a la fecha 25/10/2022</em></strong> a la Direcci&oacute;n de Planificaci&oacute;n para la gesti&oacute;n correspondiente ante la Direcci&oacute;n de Tecnolog&iacute;a de la Informaci&oacute;n y Comunicaci&oacute;n para su correspondiente actualizaci&oacute;n en la p&aacute;gina web.</span></span></span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,&quot;serif&quot;\">26/10/2022 Remisi&oacute;n de Datos estad&iacute;sticos actualizados sobre el informe de expedientes detallado <strong><em>de acuerdo a la vigencia de las leyes</em></strong>, con el respectivo an&aacute;lisis estad&iacute;stico, cotejado con el se&ntilde;or Director de Asesor&iacute;a Jur&iacute;dica. Los mismos fueron remitidos v&iacute;a Whatsapp al Se&ntilde;or Director General de Gabinete.</span></span></span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,&quot;serif&quot;\">26/10/2022 Recepci&oacute;n de Secretar&iacute;a Jur&iacute;dica el informe semanal sobre desistimiento de causas/acusaciones ingresadas.</span></span></span></span></span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,&quot;serif&quot;\">31/10/2022 Remisi&oacute;n de los Datos estad&iacute;sticos actualizados a la fecha, sobre <strong><em>Firma de Expedientes, por parte de los Miembros del Pleno</em></strong>, en formato impreso y digital a la Direcci&oacute;n de Planificaci&oacute;n y Desarrollo, y por Whatsapp al Se&ntilde;or Director General de Gabinete.</span></span></span></span></span></span></li>\r\n</ol>\r\n\r\n<p>Atentamente. -</p>\r\n\r\n<p>&nbsp;</p>\r\n',73,NULL,NULL),
