('UPDATE','2023-09-08 08:38:08',395,404,1,202,'2022-11-02 09:09:16',202,'2022-11-02 09:12:36','Solicitar Certificado de Disponibilidad Presupuestaria - CDP.','<p><strong>A </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#destinatario#</strong></p>\r\n\r\n<p><strong>De </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#remitente#</strong></p>\r\n\r\n<p><strong>Cc:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;#concopia#</strong></p>\r\n\r\n<p><strong>Asunto:&nbsp; &nbsp; &nbsp; &nbsp; #asunto#</strong></p>\r\n\r\n<p><strong>Fecha </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#fecha#</strong></p>\r\n\r\n<hr />\r\n<p>Tengo el agrado de dirigirme a usted y por su intermedio a la Direccion de Presupuesto, a los efectos de solicitar Certificado de Disponibilidad Presupuestaria - CDP,&nbsp; para la Adquisici&oacute;n de&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;, ID N&deg;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; , ID de pedido N&deg;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;, por un monto total de GS.&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;.</p>\r\n\r\n<p>Se adjunta copia de solicitud de cotizaci&oacute;n.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Atentamente. -</p>\r\n',15,NULL,NULL),
('UPDATE','2023-09-08 08:38:08',396,406,1,101,'2022-11-02 11:08:01',101,'2023-05-17 11:15:09','REMITIR DATOS ESTADÍSTICOS','<p><strong>A </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <strong>#destinatario#</strong></p>\r\n\r\n<p><strong>De </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#remitente#</strong></p>\r\n\r\n<p><strong>Cc:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;#concopia#</strong></p>\r\n\r\n<p><strong>Asunto:&nbsp; &nbsp; &nbsp; &nbsp; #asunto#</strong></p>\r\n\r\n<p><strong>Fecha </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#fecha#</strong></p>\r\n\r\n<p><strong>_________________________________________________________________________________________________________________</strong></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"background-color:white\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;\">Me&nbsp; dirijo&nbsp; a&nbsp; Usted,&nbsp; a&nbsp; efecto&nbsp; de&nbsp; poner&nbsp; a&nbsp; su&nbsp; conocimiento,&nbsp; los&nbsp; datos&nbsp; procesados&nbsp; en&nbsp; el Departamento&nbsp;&nbsp; de&nbsp;&nbsp; An&aacute;lisis&nbsp;&nbsp; y&nbsp;&nbsp; Estad&iacute;sticas,&nbsp;&nbsp; </span></span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"background-color:white\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;\">dependiente&nbsp;&nbsp; de&nbsp;&nbsp; esta&nbsp;&nbsp; Direcci&oacute;n, conforme a la Sesi&oacute;n Ordinaria de fecha 03/04/2023, &nbsp;los&nbsp; mismos&nbsp; fueron&nbsp; cotejados con Secretaria Jur&iacute;dica, </span></span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"background-color:white\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;\">seg&uacute;n detalle en los siguientes cuadros adjuntos, y se solicita la actualizaci&oacute;n en los hist&oacute;ricos referentes a estad&iacute;sticas en la p&aacute;gina web institucional.&nbsp;</span></span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"background-color:white\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;\">Los cuadros estad&iacute;sticos fueron socializados con la Se&ntilde;ora Directora de Planificaci&oacute;n y Desarrollo a trav&eacute;s del Whatsapp.</span></span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"background-color:white\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;\">En&nbsp; efecto,&nbsp; con&nbsp; ello&nbsp; se&nbsp; da&nbsp; cumplimiento&nbsp; a&nbsp; la&nbsp; remisi&oacute;n&nbsp; de&nbsp; los&nbsp; datos&nbsp; conforme&nbsp; al requerimiento del Sr. Presidente.</span></span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Atentamente,</span></span></span></span></p>\r\n',73,101,'2023-04-20 09:50:53'),
