('UPDATE','2023-09-08 08:38:08',276,303,259,3,359,'2022-10-31 16:55:52',359,'2023-03-20 13:32:23','Prov. para remitir a las dependencias para conocimiento','<p>#fecha#</p>\r\n\r\n<p>Remitir a la Mesa de Entrada Institucional, a la Oficina de Atenci&oacute;n a la Ciudadan&iacute;a y al Departamento de Archivo para su conocimiento y&nbsp;a los efectos que correspondan.</p>\r\n',58,NULL,NULL),
('UPDATE','2023-09-08 08:38:08',277,304,260,1,359,'2022-10-31 17:00:18',359,'2022-11-01 10:32:48','Formato Memorándum solicitud de informe','<p><span style=\"font-size:16px\"><strong>A </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#destinatario#</strong></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><strong>De </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#remitente#</strong></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><strong>Cc:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;#concopia#</strong></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><strong>Asunto:&nbsp; &nbsp; &nbsp; &nbsp; #asunto#</strong></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><strong>Fecha </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#fecha#</strong></span></p>\r\n\r\n<hr />\r\n<p><span style=\"font-size:16px\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,serif\">Me dirijo a Ud. con ocasi&oacute;n de hacer referencia al Informe D.A. N&deg; 20/2022 de fecha 05 de octubre de 2022, remitido por la Direcci&oacute;n de Auditoria, en el cual se eleva informe sobre la supervisi&oacute;n realizada a la Mesa de Entrada Institucional.</span></span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,serif\">Al respecto, el informe citado menciona cuanto sigue: &ldquo;<em>Se recomienda al Departamento de Mesa de Entrada Institucional, implementar una estad&iacute;stica actualizada, de los documentos recibidos en la Instituci&oacute;n</em>&rdquo;.</span></span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,serif\">En ese sentido, solicito un informe donde conste una estad&iacute;stica a la fecha de las recepciones de documentos realizadas por la dependencia a su cargo.</span></span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:16px\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,serif\">Asimismo, requiero la remisi&oacute;n mensual de un informe estad&iacute;stico con los documentos que dieron entrada en el mes respectivo.</span></span></span></span></span></p>\r\n\r\n<p><span style=\"font-size:16px\">Atentamente. -</span></p>\r\n\r\n<p>&nbsp;</p>\r\n',58,NULL,NULL),
