('UPDATE','2023-09-08 08:38:08',360,387,391,1,101,'2022-11-01 09:03:41',101,'2022-11-01 12:13:21','SOLICITAR ACTUALIZACIÓN DE DATOS ESTADÍSTICOS EN LA WEB.','<p><strong>A </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <strong>#destinatario#</strong></p>\r\n\r\n<p><strong>De </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#remitente#</strong></p>\r\n\r\n<p><strong>Cc:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;#concopia#</strong></p>\r\n\r\n<p><strong>Asunto:&nbsp; &nbsp; &nbsp; &nbsp; #asunto#</strong></p>\r\n\r\n<p><strong>Fecha </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#fecha#</strong></p>\r\n\r\n<p><strong>________________________________________________________________________________________________________</strong></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;\">Me dirijo a usted y por su intermedio a quien corresponda, con la finalidad de solicitar la actualizaci&oacute;n de los datos estad&iacute;sticos de la p&aacute;gina web, de acuerdo a los datos remitidos en formato PDF v&iacute;a mail a la Direcci&oacute;n de Planificaci&oacute;n y Desarrollo, para su correspondiente diligencia, actualizados a la Sesi&oacute;n Ordinaria de fecha 25/10/2022 y a la vez se solicita la acumulaci&oacute;n de estos datos en la pesta&ntilde;a de hist&oacute;ricos publicados de los datos estad&iacute;sticos, para poder constar como evidencia para la Secretaria Nacional de Anticorrupci&oacute;n. </span></span></span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;\">Con lo solicitado y remitido damos cumplimiento a los requerimientos del Se&ntilde;or Presidente.</span></span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:47px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,&quot;sans-serif&quot;\"><span style=\"font-size:12.0pt\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Arial&quot;,&quot;sans-serif&quot;\">Atentamente, </span></span></span></span></span></span></p>\r\n',73,NULL,NULL),
