('UPDATE','2023-09-08 08:38:08',374,401,412,1,6,'2022-11-10 08:09:07',6,'2022-11-10 08:47:18','Informe técnico retiro de equipo','<p><strong>A </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#destinatario#</strong></p>\r\n\r\n<p><strong>De </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#remitente#</strong></p>\r\n\r\n<p><strong>Cc:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;#concopia#</strong></p>\r\n\r\n<p><strong>Asunto:&nbsp; &nbsp; &nbsp; &nbsp; #asunto#</strong></p>\r\n\r\n<p><strong>Fecha </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#fecha#</strong></p>\r\n\r\n<hr />\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Tengo el agrado de dirigirme a usted a fin de comunicar que el equipo retirado del Departamento de Control y Seguimiento ya se encuentra para dar de baja debido a que la placa reparada de la PC de Marca DELL Optiplex 7040 MT con C&oacute;digo Patrimonial Numero:13.05.12.240 y Service Tag Nro.: H5CNSD2 se encuentra quemada sin posibilidad de recuperar la placa ya que estaba reparada debido a que se hab&iacute;a mojado y los integrados ya estaban comprometidos.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Acompa&ntilde;ado del equipo iba el monitor de Marca: Acer con C&oacute;digo Patrimonial Nro.13.05.10.05.00.02, &nbsp;Y Nro. de Serie: 81704729542 y teclado Marca: HP sin c&oacute;digo patrimonial.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">El equipo monitor retirado del departamento de Control y seguimiento fue instalado en la mesa de entrada de la DGAF ya que el monitor de marca HP con n&uacute;mero de serie CNC207NZXY sufri&oacute; aparentemente un golpe dejando de funcionar y se repuso con el monitor m&aacute;s arriba mencionado</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Atentamente. -</p>\r\n',61,NULL,NULL),
('UPDATE','2023-09-08 08:38:08',375,402,413,1,148,'2022-11-10 15:10:01',148,'2022-11-10 15:10:01','Socialización de fumigación de las oficinas del Edificio Sede Central y Sede II.','<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:14.0pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Garamond&quot;,serif\">&nbsp; &nbsp; &nbsp; Me dirijo a Usted a fin de socializar la <strong>CIRCULAR J.E.M./D.G.A.F./S.G. 17/2022 bis</strong>&nbsp;de fecha 10&nbsp;de noviembre&nbsp;de 2022, por la cual se comunica que el d&iacute;a viernes 11&nbsp;de noviembre&nbsp;del 2022, a partir de las <strong>17:00 horas</strong>, se llevar&aacute; a cabo la fumigaci&oacute;n de las oficinas del Edificio J.E.M. Sede Central, as&iacute; como de la Sede II</span></span></span><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Garamond&quot;,serif\">.</span></span></span></span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Garamond&quot;,serif\">&nbsp; &nbsp; &nbsp; En ese sentido, remito adjunto la mencionada circular.</span></span></span></span></span></span></span></p>\r\n',43,NULL,NULL),
('UPDATE','2023-09-08 08:38:08',376,403,414,1,197,'2022-11-11 08:11:48',197,'2022-11-11 08:11:48','Reunión','<p><span style=\"font-size:11pt\"><span style=\"line-height:115%\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:14.0pt\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Garamond&quot;,serif\">&nbsp; &nbsp; &nbsp; Me dirijo a Ustedes a efectos de convocar a una reuni&oacute;n &nbsp;el d&iacute;a mi&eacute;rcoles 16&nbsp;de noviembre de 2022,&nbsp; a las 08:00hs, en la sala de sesiones, a fin de organizar los trabajos previos y calendarizar una audiencia p&uacute;blica de rendici&oacute;n de cuentas a la sociedad, conforme al Manual de Comunicaci&oacute;n aprobado por resoluci&oacute;n de la M&aacute;xima Autoridad de la Instituci&oacute;n. </span></span></span></span></span></span></p>\r\n',43,NULL,NULL),
