('UPDATE','2023-09-08 08:38:08',383,410,421,1,359,'2022-10-31 17:00:18',466,'2022-12-02 07:37:52','Formato Memorándum Comisión','<p><span style=\"font-size:16px\"><strong>A </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#destinatario#</strong></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><strong>De </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#remitente#</strong></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><strong>Cc:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;#concopia#</strong></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><strong>Asunto:&nbsp; &nbsp; &nbsp; &nbsp; #asunto#</strong></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><strong>Fecha </strong>:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<strong>#fecha#</strong></span></p>\r\n\r\n<hr />\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Garamond&quot;,serif\">Me dirijo a Ud. con ocasi&oacute;n de poner a su conocimiento el Proyecto de Instructivo para la Destrucci&oacute;n de Documentos del Jurado de Enjuiciamiento de Magistrados elaborada por la Comisi&oacute;n conformada mediante Resoluci&oacute;n J.E.M./D.G.G./S.G. N&deg; 508/2022 y de conformidad a lo encomendado en el art&iacute;culo 2&deg; de la misma, el cual es enviado v&iacute;a correo electr&oacute;nico institucional.</span></span></span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Garamond&quot;,serif\">Al respecto, tenemos a bien solicitar previo an&aacute;lisis y consideraci&oacute;n del proyecto remitido, la realizaci&oacute;n de los procedimientos pertinentes a fin de que el mismo sea aprobado por resoluci&oacute;n de la M&aacute;xima Autoridad Institucional.</span></span></span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Garamond&quot;,serif\">Atentamente,</span></span></span></span></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n',122,NULL,NULL),
('UPDATE','2023-09-08 08:38:08',384,411,422,1,202,'2022-12-07 08:12:14',202,'2023-03-28 09:48:35','Informe Semanal','<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Goudy Old Style&quot;,serif\"><span style=\"color:#00000a\">&nbsp; &nbsp; &nbsp;Me dirijo a usted, en relaci&oacute;n al memor&aacute;ndum D.G.A.F. N&ordm; 47/2022, a los efectos de informar sobre las actividades llevadas adelante por esta direcci&oacute;n en la semana comprendida desde el 30 de noviembre al 05 de diciembre del corriente, que se detallan a continuaci&oacute;n:</span></span></span></span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Goudy Old Style&quot;,serif\"><span style=\"color:#00000a\">&nbsp; &nbsp; &nbsp;Se anexa cuadro con el detalle de los procesos y gestiones llevados adelante por esta direcci&oacute;n.</span></span></span></span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Goudy Old Style&quot;,serif\"><span style=\"color:#00000a\">&nbsp; &nbsp;</span></span></span></span></span></span></span></p>\r\n\r\n<table border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"width:500px\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"text-align:center\"><span style=\"font-size:9px\"><strong>RESUMEN DEL PAC 2023</strong></span></td>\r\n			<td style=\"text-align:center\"><span style=\"font-size:9px\"><strong>CANTIDAD</strong></span></td>\r\n		</tr>\r\n		<